import heapq

class Solution:
    def maxSpiritPower(self, N, K, M, A):
        # 前缀和与正数计数，方便快速判断
        pref = [0] * (N + 1)
        pos_cnt = [0] * (N + 1)
        for i in range(1, N + 1):
            pref[i] = pref[i - 1] + A[i - 1]
            pos_cnt[i] = pos_cnt[i - 1] + (1 if A[i - 1] > 0 else 0)

        # 全数组正数不足 K，无解
        if pos_cnt[N] < K:
            return -1

        ans = -10**18  # 足够小的初始值

        # 枚举左端点，向右扩展
        for l in range(N):
            cur_sum = 0       # 当前区间原始和
            pos_count = 0     # 当前区间正数个数
            min_heap = []     # 小顶堆，存负数绝对值（用于取最大M个）
            neg_sum = 0       # 堆中负数绝对值之和

            for r in range(l, N):
                val = A[r]
                cur_sum += val
                if val > 0:
                    pos_count += 1
                elif val < 0:
                    abs_val = -val
                    # 维护大小为 M 的小顶堆，存最大的 M 个负数绝对值
                    if len(min_heap) < M:
                        heapq.heappush(min_heap, abs_val)
                        neg_sum += abs_val
                    else:
                        # 如果当前负数绝对值比堆顶（最小的）大，替换
                        if min_heap and abs_val > min_heap[0]:
                            neg_sum -= heapq.heappop(min_heap)
                            heapq.heappush(min_heap, abs_val)
                            neg_sum += abs_val

                # 正数够 K 个时更新答案
                if pos_count >= K:
                    ans = max(ans, cur_sum + neg_sum)

        return ans if ans > -10**17 else -1
```

