import java.util.*;

class Solution {
    public long maxSpiritPower(int N, int K, int M, List<Integer> A) {
        // 前缀和与正数计数
        long[] pref = new long[N + 1];
        int[] posCnt = new int[N + 1];
        for (int i = 1; i <= N; i++) {
            pref[i] = pref[i - 1] + A.get(i - 1);
            posCnt[i] = posCnt[i - 1] + (A.get(i - 1) > 0 ? 1 : 0);
        }

        // 全数组正数不足 K，无解
        if (posCnt[N] < K) {
            return -1;
        }

        long ans = Long.MIN_VALUE;

        // 枚举左端点，向右扩展
        for (int l = 0; l < N; l++) {
            long curSum = 0;        // 当前区间原始和
            int posCount = 0;       // 当前区间正数个数
            // 小顶堆维护区间内绝对值最大的最多 M 个负数
            PriorityQueue<Long> minHeap = new PriorityQueue<>();
            long negSum = 0;        // 堆中负数绝对值之和

            for (int r = l; r < N; r++) {
                int val = A.get(r);
                curSum += val;
                if (val > 0) {
                    posCount++;
                } else if (val < 0) {
                    long absVal = -(long) val;
                    // 维护大小为 M 的小顶堆
                    if (minHeap.size() < M) {
                        minHeap.offer(absVal);
                        negSum += absVal;
                    } else {
                        // 如果当前负数绝对值比堆顶大，替换
                        if (!minHeap.isEmpty() && absVal > minHeap.peek()) {
                            negSum -= minHeap.poll();
                            minHeap.offer(absVal);
                            negSum += absVal;
                        }
                    }
                }

                // 正数够 K 个时更新答案
                if (posCount >= K) {
                    ans = Math.max(ans, curSum + negSum);
                }
            }
        }

        return ans == Long.MIN_VALUE ? -1 : ans;
    }
}
