var maxSpiritPower = function(N, K, M, A) {
    // 全数组正数不足 K，无解
    var totalPos = 0;
    for (var i = 0; i < N; i++) {
        if (A[i] > 0) totalPos++;
    }
    if (totalPos < K) return -1;

    var ans = -Infinity;

    // 枚举左端点，向右扩展
    for (var l = 0; l < N; l++) {
        var curSum = 0;
        var posCount = 0;
        // 用数组维护绝对值最大的最多 M 个负数（小顶堆性质）
        var heap = [];  // 升序数组，heap[0] 最小
        var negSum = 0;

        for (var r = l; r < N; r++) {
            var val = A[r];
            curSum += val;
            if (val > 0) {
                posCount++;
            } else if (val < 0 && M > 0) {
                var absVal = -val;
                if (heap.length < M) {
                    // 插入并维护升序（小顶堆）
                    heap.push(absVal);
                    var j = heap.length - 1;
                    while (j > 0 && heap[j] < heap[(j - 1) >> 1]) {
                        var tmp = heap[j];
                        heap[j] = heap[(j - 1) >> 1];
                        heap[(j - 1) >> 1] = tmp;
                        j = (j - 1) >> 1;
                    }
                    negSum += absVal;
                } else if (absVal > heap[0]) {
                    // 替换堆顶并下沉
                    negSum = negSum - heap[0] + absVal;
                    heap[0] = absVal;
                    var i = 0, sz = heap.length;
                    while (1) {
                        var left = 2 * i + 1, right = 2 * i + 2, smallest = i;
                        if (left < sz && heap[left] < heap[smallest]) smallest = left;
                        if (right < sz && heap[right] < heap[smallest]) smallest = right;
                        if (smallest === i) break;
                        var tmp = heap[i];
                        heap[i] = heap[smallest];
                        heap[smallest] = tmp;
                        i = smallest;
                    }
                }
            }

            // 正数够 K 个时更新答案
            if (posCount >= K) {
                var cand = curSum + negSum;
                if (cand > ans) ans = cand;
            }
        }
    }

    return ans === -Infinity ? -1 : ans;
};
