#include <stdlib.h>
#include <limits.h>

// 小顶堆：维护区间内绝对值最大的最多 M 个负数
typedef struct {
    long long data[6];  // M <= 5
    int size;
    long long sum;
} MinHeap;

// 插入一个值到小顶堆，M 为最大容量
static void heapPush(MinHeap* h, int M, long long val) {
    if (h->size < M) {
        // 堆未满，直接插入并上浮
        int i = h->size++;
        while (i > 0) {
            int p = (i - 1) / 2;
            if (h->data[p] <= val) break;
            h->data[i] = h->data[p];
            i = p;
        }
        h->data[i] = val;
        h->sum += val;
    } else if (val > h->data[0]) {
        // 堆已满，若当前值大于堆顶（最小值），则替换
        h->sum -= h->data[0];
        h->sum += val;
        h->data[0] = val;
        // 下沉
        int i = 0, sz = h->size;
        while (1) {
            int left = 2 * i + 1, right = 2 * i + 2, smallest = i;
            if (left < sz && h->data[left] < h->data[smallest]) smallest = left;
            if (right < sz && h->data[right] < h->data[smallest]) smallest = right;
            if (smallest == i) break;
            long long tmp = h->data[i];
            h->data[i] = h->data[smallest];
            h->data[smallest] = tmp;
            i = smallest;
        }
    }
}

long long maxSpiritPower(int N, int K, int M, int* A) {
    // 全数组正数不足 K，无解
    int totalPos = 0;
    for (int i = 0; i < N; i++) {
        if (A[i] > 0) totalPos++;
    }
    if (totalPos < K) return -1;

    long long ans = LLONG_MIN;

    // 枚举左端点，向右扩展
    for (int l = 0; l < N; l++) {
        long long curSum = 0;
        int posCount = 0;
        MinHeap heap;
        heap.size = 0;
        heap.sum = 0;

        for (int r = l; r < N; r++) {
            int val = A[r];
            curSum += val;
            if (val > 0) {
                posCount++;
            } else if (val < 0 && M > 0) {
                long long absVal = -(long long)val;
                heapPush(&heap, M, absVal);
            }

            // 正数够 K 个时更新答案
            if (posCount >= K) {
                long long cand = curSum + heap.sum;
                if (cand > ans) ans = cand;
            }
        }
    }

    return ans == LLONG_MIN ? -1 : ans;
}
